const body = $input.first().json.body || $input.first().json;
const sequenceType = body.sequence_type;

// Map sequence types to Brevo list IDs and automation templates
// You create these lists once in Brevo dashboard, then fill IDs here
const listMap = {
  welcome:       { list_id: 'YOUR_BREVO_WELCOME_LIST_ID',    tag: 'welcome-sequence' },
  post_purchase: { list_id: 'YOUR_BREVO_BUYERS_LIST_ID',     tag: 'buyer' },
  lead_magnet:   { list_id: 'YOUR_BREVO_LEADS_LIST_ID',      tag: 'lead-magnet' },
  newsletter:    { list_id: 'YOUR_BREVO_NEWSLETTER_LIST_ID', tag: 'newsletter' }
};

const listConfig = listMap[sequenceType] || listMap.welcome;

return [{ json: {
  ...body,
  brevo_list_id: listConfig.list_id,
  brevo_tag: listConfig.tag,
  api_key: 'YOUR_BREVO_API_KEY',
  _ready: true
}}];

// For newsletters: send as a campaign immediately
const data = $input.first().json;
const emails = data.emails || [];
const email = emails[0] || data;

return [{ json: {
  ...data,
  campaign_payload: {
    name: `Newsletter — ${email.newsletter_date || new Date().toISOString().split('T')[0]}`,
    subject: email.subject,
    htmlContent: email.html_content,
    textContent: email.text_content,
    sender: { name: 'ClearStack Studio', email: 'hello@clearstackstudio.com' },
    replyTo: 'hello@clearstackstudio.com',
    recipients: { listIds: [parseInt(data.brevo_list_id) || 1] },
    header: email.preview_text || ''
  }
}}];

// Build Brevo automation workflow for drip sequences
// Each email in the sequence becomes a step in a Brevo automation
const data = $input.first().json;
const emails = data.emails || [];

// Build steps array for Brevo automation API
const steps = emails.map((email, i) => ({
  type: 'sendEmail',
  delay: {
    value: email.send_delay_days || 0,
    unit: 'days'
  },
  email: {
    subject: email.subject,
    htmlContent: email.html_content,
    textContent: email.text_content,
    sender: { name: 'ClearStack Studio', email: 'hello@clearstackstudio.com' },
    replyTo: 'hello@clearstackstudio.com'
  }
}));

// Brevo automation trigger: contact added to specific list
const automationPayload = {
  name: data.sequence_name || `${data.sequence_type} sequence`,
  status: 'active',
  trigger: {
    type: 'contactAdded',
    listId: parseInt(data.brevo_list_id) || 1
  },
  steps: steps
};

return [{ json: {
  ...data,
  automation_payload: automationPayload,
  step_count: steps.length
}}];

// After automation is created, check if we should also add a contact immediately
const automationResult = $input.first().json;
const originalData = $('⚙️ Map Sequence to Brevo List').first().json;

return [{ json: {
  automation_id: automationResult.id,
  automation_name: automationResult.name,
  sequence_type: originalData.sequence_type,
  brevo_list_id: originalData.brevo_list_id,
  api_key: originalData.api_key,
  // If a contact email was passed (e.g. from post-purchase), add them now
  contact_email: originalData.contact_email || null,
  contact_name: originalData.contact_name || null,
  product_name: originalData.product_name || null,
  _automation_created: true
}}];

